var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"기체, 이륙합니다. 편안한 비행 되시길 바랄게요?","JPN":"機体、離陸します。快適な空の旅になりますように。","ENG":"Prepare for takeoff. I hope you all have a comfortable flight.","TWN":"機體，起飛。希望飛行順利～"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그러니까……. 레버넌트 씨가 사람 머릿속을 주무르는 걸 좋아하는 그림자라고요?","JPN":"つまり……レヴナントさんは人の頭の中をいじることが好きなシャドウ、だってことですか？","ENG":"So... Revenant is a Shadow that likes to massage peoples’ thoughts?","TWN":"你說……亡靈小姐是喜歡控制人家大腦的暗影？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사, 정신 조종이라고 해 줘.","JPN":"軍曹、精神操作って言ってよ。","ENG":"Sergeant, it’s called mind control.","TWN":"中士，你可以說是控制思想。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇게 표현하니 조금 야하게 들려.","JPN":"そんな風に表現すると、ちょっといやらしく聞こえる。","ENG":"The way you say it makes it sound a little too dirty.","TWN":"你剛的說法聽起來有點怪。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……멀쩡한 사람더러 그림자라고 하는데 절 놀릴 기분은 나요?","JPN":"……健全な一般人相手にシャドウって言ってますが、私をからかっている場合ですか？","ENG":"…Calling a normal person like you a Shadow but still you feel like joking around like this?","TWN":"……你看起來就是個人，她卻說你是暗影？現在是在耍我嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"조금만 더 가면 아주 자기들이 구 관리국인지 뭔지라고 하겠네.","JPN":"もう少ししたら自分たちが旧管理局だのなんの言い出しそう。","ENG":"Next you’ll be telling us you’re some Old Administration mumbo jumbo.","TWN":"等一下該不會跟我說你們是舊管理局的人吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"응. 맞아. 역시 똘똘하잖아, 중사님.","JPN":"うん。そうなの。やっぱりお利口じゃない、軍曹。","ENG":"Yes. Very clever, Sergeant.","TWN":"喔！沒錯喔！你果然很聰明呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어……. 무임승차했다고 아주 맘대로 말하시네.","JPN":"は……ただ乗りだからって好き勝手言ってますね。","ENG":"Huh... So you’re saying whatever you want just because you gave us a free ride.","TWN":"呃……就算我搭機沒付錢，也不用說話戲弄我吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"모르스에게 날아들었던 포격을 생각하면 못 믿을 이야기도 아니지만…….","JPN":"モールスに飛んできた砲撃を考えると、まったく信じられない話でもないけど……","ENG":"It’s not such an unbelievable story when I think of the artillery barrage on Mors.","TWN":"想到朝莫爾斯飛過去的砲擊，也不是毫無可能……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"결국 그 저격수에게 공격 받은 이유가 그림자이기 때문이란 건가?","JPN":"結局あのスナイパーに狙われた理由って、シャドウだからってことなのかな？","ENG":"So the reason that sniper attacked us is because I’m a Shadow?","TWN":"結果我遭到狙擊手的攻擊，是因為我是暗影嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"내가 인간으로 의태한 그림자라서?","JPN":"私が人間に擬態したシャドウだから？","ENG":"Because I’m a Shadow that mimics humans?","TWN":"我是擬態成人類的暗影嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼 이상하지 않아? 어째서 내 주위에 침식 증후군 환자가 줄을 잇지 않았던 건데?","JPN":"だとしたらおかしくない？　なんで私の周りに侵食症候群の患者が発生しなかったわけ？","ENG":"If that’s true, then isn’t it kind of weird? How come there aren’t a lot of people with Corruption Syndrome around me?","TWN":"可是不太對吧？為什麼我身邊沒有侵蝕症候群的患者呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"방금 말한 대로, 마에스트로는 현실에 부상할 당시에 이미 소멸을 앞두고 있었어.","JPN":"先にも言ったけど、マエストロは現実世界に浮上する当時、すでに消滅寸前だったの。","ENG":"As I was just explaining, Maestra was already on the verge of vanishing when she remerged into the Normalside.","TWN":"就像我剛才說的，指揮家躍入現實世界時，已經是命在旦夕。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"침식파를 방출하기는커녕 현실세계에서 머물기에도 힘들었으니…….","JPN":"侵食波の放出はおろか、現実世界にとどまることさえ難しかったから……","ENG":"It was hard enough to stay in Normalside, let alone release Corruption rays...","TWN":"別說釋放什麼侵蝕波，光是要在現實世界存活下去都很困難……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"의태라기보다 일종의 휴면 상태에 들어갔다고 봐야겠지.","JPN":"擬態というより、一種の休眠状態に入ったって言うべきでしょうね。","ENG":"More than mimicry, she’s in kind of a dormant state.","TWN":"與其說是擬態，應該說是進入某種休眠狀態。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그런 말도 안 되게 희귀한 케이스는 결국 추측하기 나름이잖아.","JPN":"そんなあり得ないくらい稀なケースは、結局推測次第でどうとでもなるじゃない。","ENG":"Such an extremely rare case is essentially just an assumption.","TWN":"這麼荒謬言論，說到底是你個人的猜測吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뭣보다 내 머릿속엔 어릴 때 기억도 전부, 똑똑히 들어 있어.","JPN":"何より、私の頭の中には小さい頃の記憶も全部、はっきり残ってる。","ENG":"I still remember everything from my childhood.","TWN":"而且從小到大的記憶我都記得很清楚，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"먼저 세상을 떠난 아버지도, 어머니의 젊었을 적 얼굴도 전부.","JPN":"亡くなったお父さんも、若い頃のお母さんの顔まで全部。","ENG":"My father, who died first, and even my mother’s face when she was younger.","TWN":"像是英年早逝的爸爸，還有媽媽年輕時候的模樣，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마는 알잖아요. 그 날 건국기념전당 앞에서 무슨 일이 있었는지.","JPN":"お母さんは知ってるでしょう？　あの日、建国記念館の前で何があったか。","ENG":"Mom, you know it too. What happened that day in front of the National Foundation Hall.","TWN":"媽你也記得吧？那天在建國紀念堂前面發生的事。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응…….","JPN":"ううん……","ENG":"Erm...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마?","JPN":"お母さん？","ENG":"Mom?","TWN":"媽？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"마, 말 못 해……. 말하면 안 된댔어…….","JPN":"い、言えない……言ってはいけないって……","ENG":"I-I can’t say... They said I wasn’t allowed to say anything...","TWN":"不…不可以說……她說不可以說……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"누가…… 누가 말하지 말라고 했는데?","JPN":"誰が……誰が言うなって言ったの？","ENG":"Who... Who said you weren’t allowed to say?","TWN":"誰……誰說不可以說的？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"초, 총 든 사람들…….","JPN":"じゅ、銃を持った人たち……","ENG":"P-People with guns...","TWN":"拿…拿槍的人……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"군인들이……. 너, 너를 데려가려고…….","JPN":"軍人が……あ、あなたを連れて行こうと……","ENG":"Those soldiers... Th-they took you...","TWN":"那些軍人……要把你帶走……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아, 아아…….","JPN":"あ、ああ……","ENG":"Ah... Aah...","TWN":"啊啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아무도 내 말을 안 믿어 줘요. 우리 딸애인데, 우리 딸애가 맞는데…….","JPN":"誰も私の言葉を信じてくれないんです。私の娘なのに、確かに私の娘なのに……","ENG":"Nobody believes me. She’s my daughter, she’s my daughter...","TWN":"沒有人相信我的話，你是我的女兒，你真的是我的女兒……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"무슨 소리야……? 군인이라니, 군인들이 와서 뭘 어떻게 했는데?","JPN":"どういうこと……？　軍人って、軍人が来て何をどうしたの？","ENG":"What are you talking about...? Soldiers? What did the soldiers do?","TWN":"媽你在說什麼……？什麼軍人？那些軍人做了什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아아아아악!!","JPN":"あああああ！！","ENG":"Aaahhhh!!","TWN":"啊啊啊啊啊！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"하지 마, 우리 딸이야! 우리 딸이 맞아!! 아아아아악!!","JPN":"ダメ、私の娘なの！　本当にうちの娘なの！！　あああああ！！","ENG":"Stop! That’s my daughter! My daughter! Ahhhh!!","TWN":"不要！她是我的女兒！我沒說謊！！啊啊啊啊！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마, 제발……!","JPN":"お母さん、お願い……！","ENG":"Mom, please...!","TWN":"媽，我拜託你……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"말해, 좀!! 비명만 지르지 말고……! 왜 말을 못하는 건데! 왜!!","JPN":"話してよ！！　悲鳴ばっか上げないで……！　なんで言えないの！　なんで！！","ENG":"Tell me, please!! Stop screaming! Why can’t you just tell me? Why!!","TWN":"我拜託你說話！！不要只是尖叫……！到底是什麼事不可以說！為什麼！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그만해요, 레버넌트 씨! 아주머니 정신 상태가 안 좋다는 건 본인이 말한 거잖아요!","JPN":"やめてください、レヴナントさん！　おばさんの精神が不安定だって自分で言ってたじゃないですか！","ENG":"Stop, Revenant! You said your mom’s mental state wasn’t good!","TWN":"亡靈小姐，你不要這樣！不是你自己說伯母的精神狀態不好嗎！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아주머니, 심호흡하세요. 무서워하지 않아도 돼요.","JPN":"おばさん、深呼吸してください。怖がらなくていいですよ。","ENG":"Madam, take a deep breath. You don’t have to be scared.","TWN":"伯母，你先深呼吸，別怕。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"우리, 우리 딸은 아무 잘못 안 했어요……. 정말이에요…….","JPN":"わた、私の娘は何も悪くないんです……本当です……","ENG":"My, my daughter didn’t do anything wrong... I’m telling you, please...","TWN":"我女兒…我女兒沒做壞事……是真的……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"알아요, 아주머니.","JPN":"わかってます、おばさん。","ENG":"I know, Madam.","TWN":"我知道。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이 훈장 아시죠? 전 무공 훈장 수훈자예요.","JPN":"この勲章、わかりますよね？　私は受勲者なんですよ。","ENG":"You recognize this medal? I’m a war hero.","TWN":"伯母，你看這個勳章，我是授勳者喔。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제가 다른 군인들한테 잘 얘기해 둘게요. 그러니까 무서워하실 필요 없어요.","JPN":"私が他の軍人たちによく話しておきます。だから怖がる必要はありません。","ENG":"I’ll talk to the other soldiers for you. So there’s no need to be scared.","TWN":"我會跟其他軍人說清楚的，你別怕。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"흑……. 흐흑…….","JPN":"う……ううっ……","ENG":"Sniffle... Hnnggg...","TWN":"呼……呼呼……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……미안해, 엄마. 내가 지나쳤어.","JPN":"……ごめんね、お母さん。私がやり過ぎた。","ENG":"I'm sorry, Mom. I went too far.","TWN":"……媽，對不起，是我太激動了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"꽤 침착하네. 비슷한 경험이 있었나 봐?","JPN":"結構落ち着いてるのね。似たようなことがあったの？","ENG":"You seem quite calm. This must have happened before?","TWN":"你的應對很沉著呢，是之前有類似的經歷嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"신병들이 전쟁터에서 보이는 모습이랑 비슷하더라고요. 저도 첫 전투 때 패닉에 빠져서 적 대신 우리 편을 쏠 뻔했어요.","JPN":"新兵が戦場で見せる姿と似てるんです。私も初戦闘でパニックになって敵じゃなく味方を撃とうとしてたんですよね。","ENG":"It’s pretty similar to how new recruits act on the battlefield. My first battle, I panicked and almost shot our own side instead of the enemy.","TWN":"她的反應，就和那些初次上戰場的菜鳥一樣。我第一次上戰場時，也是緊張到差點朝我們自己人開槍。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭐……. 방금 들은 대로, 당시에 반정부 단체들은 개입하지 않았어.","JPN":"まあ……今聞いたとおり、当時反政府団体は介入してなかった。","ENG":"Well... As you heard, anti-government organization wasn’t the one who intervened.","TWN":"總之……如同你們剛才所聽到的，當時反政府團體並未介入。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당시엔 원인 불명의 사고로 처리됐지. 이면세계의 존재가 알려지지 않았을 무렵이니까.","JPN":"その時には原因不明の事故ってことになったの。裏世界の存在が知られてない頃だったからね。","ENG":"Back then, it was said to be an accident of unknown causes. Back when the existence of Counterside was still unknown.","TWN":"當時是以意外作為結案，因為當時大家還不曉得異界的存在。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만…… 안타까운 사고도 어떤 사람들 눈에는 다른 쓰임새가 보이지 않았으려나.","JPN":"でも……残念な事故でも、ある人たちの目には別の使いどころが見えたんじゃないかな。","ENG":"But... some people might have been able to use this unfortunate accident to their own advantage.","TWN":"只是……這件意外遭到有心人士利用。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"위성 영상으로 레버넌트 씨가 말한 저격수의 인상착의를 분석해 봤어.","JPN":"衛星の映像からレヴナントさんが言ってたスナイパーの人物像を分析してみたの。","ENG":"I analyzed the description of the sniper Revenant mentioned using satellite images.","TWN":"我們根據衛星影像，試著分析你說的那個狙擊手的衣著和長相，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"본명은 피오 바르거스. 예전에 사용하던 코드명은 몽타뉴.","JPN":"実名ピオ・バルガス。昔使ってたコードネームはモンターニュ。","ENG":"Her real name is Pio Vargas. Her codename she used earlier, is Montagne.","TWN":"她的本名叫妃歐·巴克斯，以前的代號是蒙塔妮。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"마에스트로에게 부대원과 오빠를 잃었던, 우리 옛 동료야.","JPN":"マエストロに部隊員とお兄さんを殺された、私たちの昔の仲間よ。","ENG":"An old colleague of ours, who lost her entire unit and brother to Maestra.","TWN":"是我們的老同事，她的哥哥和戰隊員全都死於指揮家之手。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"오빠를…….","JPN":"お兄さんを……","ENG":"Her brother...","TWN":"她的哥哥……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"게다가 이 지역에 마에스트로의 휘하에 있던 그림자들까지 출몰했지.","JPN":"しかもこの地域にマエストロの旗下にいたシャドウたちも現れた。","ENG":"That’s not all, Shadows serving Maestra have appeared in this region.","TWN":"另外，指揮家手下的暗影，也曾經在這個地區出沒。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"우리는 이 길로 가서 너희 모녀를 다른 나라의 정보 기관으로 인계할 계획이야.","JPN":"私たちはこのままあなたたち親子を他国の情報機関に渡すつもりよ。","ENG":"We plan to hand over both of you, mother and daughter, to another country’s intelligence agency.","TWN":"我們打算走這條路，將你們母女交接給另一個國家的情報機關。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그쪽도 흔쾌히 적극적인 협조를 약속했지. 짚이는 일이 있어서 그러려나?","JPN":"あちらも喜んで積極的に協力すると約束してくれたの。心当たりがあるのかな？","ENG":"They promised active cooperation. They must have some sort of insight into the situation?","TWN":"對方也很爽快地答應會提供協助，可能他們也有預料到吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저, 저도 망명 신청하면 받아 주나요?","JPN":"わ、私も亡命を申し込んだら受け入れてくれますか？","ENG":"Uh, will they accept me too if I apply for asylum?","TWN":"那個，我也可以申請逃亡海外嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"잘 얘기해 볼게, 중사님. 미리 홍차에 대해 배워 두면 좋을 거야.","JPN":"話しを通してみるよ、軍曹。あらかじめ紅茶について勉強しておくとよさそうね。","ENG":"I’ll put in a good word for you, Sergeant. But I would advise you to learn all there is to know about black tea in advance.","TWN":"我再跟對方說說看，不過你最好先學習一下有關紅茶的知識。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"홍차……?","JPN":"紅茶……？","ENG":"Black tea...?","TWN":"紅茶……？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"알렉스 씨, 미안하지만 나는…….","JPN":"アレックスさん、悪いけど私は……","ENG":"Alex, I’m sorry but I—","TWN":"雅蕾克絲，不好意思，我……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 대공 포격?!","JPN":"な、なに？　対空砲撃！？","ENG":"W-what happened? Anti-aircraft missiles?","TWN":"這是怎樣？對空砲擊？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"모네카! 상황 보고해, 어서!","JPN":"モネカ！　状況を報告しなさい、早く！","ENG":"Moneka! Report the situation, now!","TWN":"莫奈卡！立刻回報現況！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"4번 고정포대로 사용되던 에스타크입니다! 추진기가 피격당했습니다!","JPN":"第4番の固定砲台として使われていたエスタークです！　推進機が撃たれました！","ENG":"It’s Estaque! Used as Defence Turret 4, our thrusters have been hit!","TWN":"是拿來當作4號固定砲台使用的艾斯塔克！推進器受損！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"상태로 보아 구 관리국의 원본 운영체계를 복구한 것으로 추정됩니다!","JPN":"状況から察するに、旧管理局のオリジナルシステムを復旧したことと推定されます！","ENG":"Looking at its current state, it appears that the original operating system from the Old Administration has been restored!","TWN":"看狀態，應該是將舊管理局原本的操作系統進行復原！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"제길…… 살다가 공중에서 에스타크한테 다 맞아 보네.","JPN":"くそ……空中でエスタークの攻撃をくらうのは初めてよ。","ENG":"Crap... Never thought we would be hit by the Estaque mid-air.","TWN":"該死……沒想到會在空中被艾斯塔克擊中。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"히잉, 그러게요! 수송 목적으로 생산된 기체다 보니……!","JPN":"ふえん、そうなんです！　輸送のために生産された機体ですので……！","ENG":"Hnng, yes! The body of the transport was only designed to transport...!","TWN":"嗚嗚，對啊！因為這台是專門用來運輸的……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"지금 애교 부릴 때야? 다 죽는 꼴 보기 싫으면 어떻게든 불시착시켜!","JPN":"愛嬌振りまいてる場合？　全員を死なせたくなかったらどうにかしてでも不時着しなさい！","ENG":"Is this really the time for the cute baby talk? If you don’t want to see us all die, figure out a way to crash-land us safely!","TWN":"現在是哭哭啼啼的時候嗎？不想大家一起死，就趕快想辦法緊急降落！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"앗, 네! 다들 꽉 잡으세요!","JPN":"ああっ、はい！　皆さん、しっかり掴まってください！","ENG":"Oh, understood! Everyone, hold on tight!","TWN":"是，好！請大家抓緊囉！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"크으…….","JPN":"くぅ……","ENG":"Kgh...!","TWN":"呃……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사! 엄마!! 대답해!","JPN":"軍曹！　お母さん！！　返事して！","ENG":"Sergeant! Mom!! Come in!","TWN":"中士！媽！回答我！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"여기요! 아주머니는 무사하세요!","JPN":"ここです！　おばさんは無事ですよ！","ENG":"Here! Your mom is safe, too!","TWN":"我在這裡！伯母沒事！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"내 이민의 꿈은 박살이 나 버렸지만…….","JPN":"移民するという私の夢はぶち壊されてしまったけど……","ENG":"My dreams of immigration have been destroyed though...","TWN":"不過我的移民夢碎……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"에구, 손님……. 그로니아는 좋은 나라란다…….","JPN":"まあ、お客さん……グロニアはいい国よ……","ENG":"Oh no, my guest... Gronia is a wonderful country.","TWN":"哎呀，可愛的客人……格羅尼亞是很棒的國家喔……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……하. 하. 유머 감각이 장난 없으시네요.","JPN":"……は。は。半端ないギャグセンスですね。","ENG":"…Ha. Ha. You have a great sense of humor.","TWN":"……哈，哈。伯母你真幽默。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"과부하로 뻗었을 에스타크를 고친 걸 보니…… 몽타뉴 짓인가?","JPN":"過負荷で伸びたはずのエスタークを直したところをみると……モンターニュの仕業かな？","ENG":"They were able to fix the Estaque... Was it Montagne who did it?","TWN":"竟然可以修好艾斯塔克……是蒙塔妮嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"부전대장님! 기체를 격추시킨 4번 에스타크의 포신 각도가 조정 중입니다!","JPN":"副戦隊長！　機体を撃墜した第3番エスタークの砲身角度が調整されています！","ENG":"Deputy Commander! The turret of Estaque 3, which brought down our transport, is adjusting its aim!","TWN":"副戰隊長！擊落機體的3號艾斯塔克正在調整砲身角度！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"계산대로라면, 예상 착탄 지점은 중앙대로예요!","JPN":"計算どおりなら、予想着弾地点は中央通りです！","ENG":"According to my calculations, the estimated crash point is the main street!","TWN":"按照計算，預計落彈地點會在央大道！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……예고르, 애들 전투 준비시켜. 출격한다.","JPN":"……イェゴール、子どもたちに戦闘準備を。出撃するわ。","ENG":"...Yegor, prepare the kids for battle.","TWN":"……伊高爾，叫孩子們進入備戰狀況！出擊！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"곱게 끝나는 법이 없군요. 알겠습니다.","JPN":"穏便に収まることがありませんね。了解しました。","ENG":"It never goes smoothly. Roger that.","TWN":"是！想要好來好去果然是奢望。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"레버넌트 씨, 당신은 두 사람이랑 여기 남아 있도록 해.","JPN":"レヴナントさん、あなたはこの二人とここに残りなさい。","ENG":"Revenant, you stay here with these two.","TWN":"亡靈，你和他們兩個留在這裡。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"위험한 녀석이 접근하면 모네카가 경고해 줄 거야.","JPN":"危ない奴が近づいたらモネカが警告してくれるはずよ。","ENG":"Moneka will warn you if anyone dangerous approaches.","TWN":"若是有危險人物靠近，莫奈卡會警告你們的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"알겠어. 부탁할게.","JPN":"わかった。任せるよ。","ENG":"Understood. You take care.","TWN":"好，麻煩了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};